{
  "query": "mutation SubmitFeedback($insightId: ID!, $rating: String!, $comment: String) {
  submitFeedback(insightId: $insightId, rating: $rating, comment: $comment) {
    id
    insightId
    rating
    comment
    createdAt
  }
}",
  "variables": { "insightId": "{{insightId}}", "rating": "helpful", "comment": "Correctly identified a real duplicate." }
}
